(function(){"use strict";var data=window.hivepressActionBarFrontendData||{},bar=document.querySelector(".hp-action-bar");if(!bar){return}if(data.safeArea){var meta=document.querySelector('meta[name="viewport"]');if(meta){var content=meta.getAttribute("content")||"";if(content.indexOf("viewport-fit")===-1){meta.setAttribute("content",content?content+",viewport-fit=cover":"viewport-fit=cover")}}}var path=window.location.pathname.replace(/\/+$/,"")||"/";Array.prototype.forEach.call(bar.querySelectorAll(".hp-action-bar__item"),function(item){var href=item.getAttribute("href");if(!href){return}var link=document.createElement("a");link.href=href;if(link.host!==window.location.host){return}var linkPath=link.pathname.replace(/\/+$/,"")||"/";if(linkPath===path){item.classList.add("hp-action-bar__item--active");item.setAttribute("aria-current","page")}});if(data.badge&&data.ajaxURL&&window.fetch){var badges=bar.querySelectorAll(".hp-action-bar__badge");if(badges.length){var applyCount=function(count){count=parseInt(count,10)||0;Array.prototype.forEach.call(badges,function(badge){if(count>0){badge.textContent=count>99?"99+":String(count);badge.removeAttribute("hidden")}else{badge.setAttribute("hidden","hidden")}})};var cacheKey="hpActionBarBadge",now=Date.now(),cached=null;try{cached=JSON.parse(window.sessionStorage.getItem(cacheKey))}catch(e){cached=null}if(cached&&typeof cached.time==="number"&&now-cached.time<6e4){applyCount(cached.count)}else{window.fetch(data.ajaxURL+"?action=hp_action_bar_badge",{credentials:"same-origin"}).then(function(response){return response.json()}).then(function(response){var count=response&&response.data?response.data.count:0;applyCount(count);try{window.sessionStorage.setItem(cacheKey,JSON.stringify({time:now,count:count}))}catch(e){}}).catch(function(){})}}}})();
